import numpy as npimport jsonfrom astropy.io import fitsfrom dataclasses import dataclassfrom criresviz.skycalc import compute_sky@dataclass(slots=True)class Sky:    wavelength: np.ndarray    transmission: np.ndarray    radiance: np.ndarray    parameters: dict    """    Properties    """    @property    def wavelength_range(self):        return (            self.wavelength.min(),            self.wavelength.max(),        )    @property    def transmission_range(self):        return (            self.transmission.min(),            self.transmission.max(),        )    @property    def radiance_range(self):        return (            self.radiance.min(),            self.radiance.max(),        )    @property    def mean_transmission(self):        return self.transmission.mean()    @property    def available_parameters(self):        """Return all available SkyCalc parameters."""        return sorted(self.parameters.keys())        """    Methods    """    @classmethod    def from_file(cls, filename):        with fits.open(filename) as hdul:            table = hdul[1].data            header = hdul[0].header            wavelength = table["lam"]/1000            transmission = (                table["trans_ma"]                * table["trans_o3"]                * table["trans_rs"]                * table["trans_ms"]            )            radiance = (                table["flux_sml"]                + table["flux_ssl"]                + table["flux_zl"]                + table["flux_tie"]                + table["flux_tme"]                + table["flux_ael"]                + table["flux_arc"]            )                        comments = "\n".join(header["COMMENT"])                        start = comments.find("{")            end = comments.rfind("}") + 1                        parameters = json.loads(                comments[start:end]            )        return cls(            wavelength=wavelength,            transmission=transmission,            radiance=radiance,            parameters=parameters,        )        ##############################################    @classmethod    def from_skycalc(cls, **kwargs):        filename = compute_sky(**kwargs)        return cls.from_file(filename)        '''    Functions    '''    def get_parameter(self, *names):        """Return one or more SkyCalc parameters."""            if len(names) == 1:            return {names: self.parameters[names[0]]}            return {name: self.parameters[name] for name in names}        ##############################################        def plot(self, ax=None):        from criresviz.plotting.sky import _draw_sky        return _draw_sky(self, ax)        ##############################################        def __str__(self):        wmin, wmax = self.wavelength_range        return (            "Sky\n"            "──────────────────────────────\n"            f"Airmass:          {self.parameters['airmass']:.2f}\n"            f"Wavelength:       {wmin:.2f}–{wmax:.2f} nm\n"            f"Wavelength resolution: {self.parameters['wres']}\n"            f"Precipitable water vapour: {self.parameters['pwv']:.2f}\n"            f"Observatory: {self.parameters['observatory']}\n"            f"Molecular Emission of Upper Atmosphere: {self.parameters['incl_upperatm']}\n"            f"Molecular Emission of Lower Atmosphere: {self.parameters['incl_loweratm']}\n"        )        